import{_ as a,o as e,c as l,ag as r}from"./chunks/framework.DSqpaH5Z.js";const P=JSON.parse('{"title":"서비스 개요","description":"AI 여행 플래너 서비스 개요, 차별점, 수익 모델, 개발 로드맵","frontmatter":{"title":"서비스 개요","description":"AI 여행 플래너 서비스 개요, 차별점, 수익 모델, 개발 로드맵"},"headers":[],"relativePath":"01-overview.md","filePath":"01-overview.md"}'),i={name:"01-overview.md"};function d(h,t,o,s,n,c){return e(),l("div",null,[...t[0]||(t[0]=[r('<h2 id="한-줄-정의" tabindex="-1">한 줄 정의 <a class="header-anchor" href="#한-줄-정의" aria-label="Permalink to &quot;한 줄 정의&quot;">​</a></h2><p><strong>&quot;조건 몇 가지만 입력하면, AI가 완성된 여행 일정을 만들어준다&quot;</strong></p><p>여행 계획에 드는 수고를 최소화하는 AI 기반 여행 플래너. 계획부터 실행까지 하나의 앱에서 끝낸다.</p><ul><li><strong>초기 지원 국가:</strong> 한국, 일본</li><li><strong>핵심 타겟:</strong> 여행 계획을 직접 짜고 싶지만 귀찮은 사람 (계획형 J)</li></ul><hr><h2 id="차별점" tabindex="-1">차별점 <a class="header-anchor" href="#차별점" aria-label="Permalink to &quot;차별점&quot;">​</a></h2><table tabindex="0"><thead><tr><th>기존 서비스</th><th>우리 서비스</th></tr></thead><tbody><tr><td>직접 검색하고 조합해야 함</td><td>조건 입력만 하면 완성 일정 생성</td></tr><tr><td>결과가 하나뿐</td><td>3~4개 옵션 중 선택</td></tr><tr><td>지도/맛집/예약 앱이 따로</td><td>하나의 앱에서 통합 제공</td></tr><tr><td>계획 후 실행이 분리됨</td><td>계획 → 실행까지 연속 지원</td></tr><tr><td>혼자만 볼 수 있음</td><td>친구와 공유 + 공동 열람</td></tr></tbody></table><p><strong>벤치마크:</strong> 야놀자 (예약) + 구글맵 (루트) + 스카이스캐너 (가격) 를 하나로 합친 서비스</p><hr><h2 id="수익-모델" tabindex="-1">수익 모델 <a class="header-anchor" href="#수익-모델" aria-label="Permalink to &quot;수익 모델&quot;">​</a></h2><table tabindex="0"><thead><tr><th>단계</th><th>모델</th><th>내용</th></tr></thead><tbody><tr><td>Phase 1</td><td>광고</td><td>구글 애즈</td></tr><tr><td>Phase 2</td><td>건당 과금</td><td>일정 생성 1회 1,000원</td></tr><tr><td>Phase 2</td><td>제휴 수수료</td><td>예약 앱 연결 시 수수료</td></tr><tr><td>Phase 3</td><td>예약 대행 수수료</td><td>전체 예약 대행 시 약 1만원</td></tr></tbody></table><hr><h2 id="개발-로드맵" tabindex="-1">개발 로드맵 <a class="header-anchor" href="#개발-로드맵" aria-label="Permalink to &quot;개발 로드맵&quot;">​</a></h2><h3 id="phase-1-mvp" tabindex="-1">Phase 1 - MVP <a class="header-anchor" href="#phase-1-mvp" aria-label="Permalink to &quot;Phase 1 - MVP&quot;">​</a></h3><ul><li>[ ] 웹 메인 페이지 (검색 + 인기 여행지 카드)</li><li>[ ] 여행 조건 입력 플로우 (자유 입력 포함)</li><li>[ ] AI 2단계 호출 (후보 3~4개 → 선택 → 상세)</li><li>[ ] 후보 계획 저장 및 선택 UI</li><li>[ ] 지도 전체뷰 + 스텝 검토 뷰 (줌 애니메이션)</li><li>[ ] Google Places API 연동</li><li>[ ] Amadeus API 연동</li><li>[ ] 카카오톡 공유 + 공개 웹 페이지</li><li>[ ] 친구 초대 (공동 열람)</li><li>[ ] 관리자 페이지 (여행지 관리 + 계획 대량 생성)</li><li>[ ] 구글 애즈 세팅</li></ul><h3 id="phase-2-고도화" tabindex="-1">Phase 2 - 고도화 <a class="header-anchor" href="#phase-2-고도화" aria-label="Permalink to &quot;Phase 2 - 고도화&quot;">​</a></h3><ul><li>[ ] Naver Local Search API 연동</li><li>[ ] 공동 편집</li><li>[ ] 예약 앱 딥링크 연결</li><li>[ ] 일정 생성 유료화 (1,000원/회)</li><li>[ ] 여행 실행 모드 (GPS 기반)</li><li>[ ] Best 여행계획 카탈로그 (데이터 누적 후)</li></ul><h3 id="phase-3-예약-대행" tabindex="-1">Phase 3 - 예약 대행 <a class="header-anchor" href="#phase-3-예약-대행" aria-label="Permalink to &quot;Phase 3 - 예약 대행&quot;">​</a></h3><ul><li>[ ] Toss Payments 통합 결제</li><li>[ ] 예약 자동화</li><li>[ ] 수수료 모델 (약 1만원/건)</li></ul>',19)])])}const p=a(i,[["render",d]]);export{P as __pageData,p as default};
